import './index.css';

import {
  Link
} from 'react-router-dom';

function TeacherHeader() {

  const userString =
    localStorage.getItem('user');

  let user = {};

  try {

    user = userString
      ? JSON.parse(userString)
      : {};

  } catch (error) {

    console.log(error);

  }

  // LOGOUT
  const logout = () => {

    localStorage.clear();

    window.location.href = '/';

  };

  return (

    <div className="teacher-header">

      {/* LOGO */}

      <div className="teacher-logo">

        Teacher Portal

      </div>


      {/* NAVIGATION */}

      <div className="teacher-links">

        <Link to="/teacher-dashboard">

          Dashboard

        </Link>

        <Link to="/subjects">

          Subjects

        </Link>

        <Link to="/add-student">

          Students

        </Link>

        <Link to="/add-marks">

          Marks

        </Link>

        <button
          onClick={logout}
        >

          Logout

        </button>

      </div>

    </div>

  );

}

export default TeacherHeader;
